custom_css:
/* ── Crystal Century custom styles ── */

/* Typography */
body{-webkit-font-smoothing:antialiased;-moz-osx-font-smoothing:grayscale}
a:not(.elementor-button):not(.button):not(.cc-enquiry-btn){color:inherit;text-decoration:none}
a:not(.elementor-button):not(.button):not(.cc-enquiry-btn):hover{color:#b8960c}
.elementor-widget-heading .elementor-heading-title{line-height:1.3}

/* Header nav */
.elementor-nav-menu .elementor-item{letter-spacing:.05em;font-weight:500!important;transition:color .18s}

/* Hide cart UI — catalogue mode */
.elementor-menu-cart__wrapper,.elementor-menu-cart__container,.woocommerce-mini-cart,
a.cart-contents,.wc-block-mini-cart,.widget_shopping_cart,.cart-icon,
.cc-cart-count{display:none!important}

/* Hide prices globally */
.woocommerce-Price-amount.amount{display:none}
.woocommerce-cart .woocommerce-Price-amount.amount,
.woocommerce-checkout .woocommerce-Price-amount.amount{display:inline!important}

/* Hero — text overlay */
.elementor-element-cc_herolay{position:absolute!important;inset:0!important;z-index:5!important;background:linear-gradient(to right,rgba(10,10,10,.62) 40%,rgba(10,10,10,.12) 100%)!important;display:flex!important;flex-direction:column!important;justify-content:flex-end!important;padding:0 7% 6%!important;pointer-events:none}
.elementor-element-cc_herolay *{pointer-events:auto}
.elementor-element-cc_htag .elementor-heading-title{color:#fff!important;font-size:clamp(1.7rem,4vw,2.8rem)!important;font-weight:700!important;line-height:1.25!important;text-shadow:0 1px 6px rgba(0,0,0,.4);margin-bottom:.4em}
.elementor-element-cc_hsub .elementor-text-editor p{color:rgba(255,255,255,.9)!important;font-size:.95rem!important;margin-bottom:1.2em;letter-spacing:.04em}
.elementor-element-cc_hbtn .elementor-button{background-color:#b8960c!important;border-color:transparent!important;color:#fff!important;font-weight:600!important;letter-spacing:.05em;border-radius:2px!important;transition:background .2s,transform .15s!important}
.elementor-element-cc_hbtn .elementor-button:hover{background-color:#8a6e0a!important;transform:translateY(-1px)}

/* Category grid */
.elementor-element-cc_catsec{background:#f9f7f4!important}
.elementor-element-cc_cattitle .elementor-heading-title{font-size:clamp(1rem,2.5vw,1.3rem)!important;font-weight:700!important;letter-spacing:.18em;color:#1a1a1a!important;position:relative;padding-bottom:.6em}
.elementor-element-cc_cattitle .elementor-heading-title::after{content:'';display:block;width:36px;height:3px;background:#b8960c;margin:10px auto 0}
.elementor-element-cc_catgrid .elementor-shortcode{max-width:1120px;margin:0 auto;width:100%;display:flex!important;flex-wrap:wrap!important;justify-content:center!important;gap:16px!important}
.elementor-element-cc_catgrid{width:100%!important;max-width:100%!important}
.elementor-element-cc_catgrid .elementor-widget-image-box{flex:0 0 calc(25% - 12px);min-width:160px;max-width:220px;box-sizing:border-box}
.elementor-element-cc_catgrid .elementor-image-box-wrapper{background:#fff;border:1px solid #e8e3db;border-radius:6px;overflow:hidden;transition:box-shadow .2s,transform .2s;text-align:center;height:100%;padding-bottom:14px}
.elementor-element-cc_catgrid .elementor-image-box-wrapper:hover{box-shadow:0 6px 22px rgba(0,0,0,.1);transform:translateY(-3px)}
.elementor-element-cc_catgrid .elementor-image-box-img{margin-bottom:0;overflow:hidden}
.elementor-element-cc_catgrid .elementor-image-box-img img{width:100%;height:150px;object-fit:cover;display:block;transition:transform .35s}
.elementor-element-cc_catgrid .elementor-image-box-wrapper:hover img{transform:scale(1.04)}
.elementor-element-cc_catgrid .elementor-image-box-content{padding:10px 8px 0}
.elementor-element-cc_catgrid .elementor-image-box-title{font-size:.88rem!important;font-weight:600!important;color:#1a1a1a!important;letter-spacing:.04em;margin:0!important}
@media(max-width:900px){.elementor-element-cc_catgrid .elementor-widget-image-box{flex:0 0 calc(33.333% - 12px)}}
@media(max-width:600px){.elementor-element-cc_catgrid .elementor-widget-image-box{flex:0 0 calc(50% - 8px);min-width:120px}}

/* WooCommerce — product cards */
.woocommerce ul.products{margin:0!important}
.woocommerce ul.products li.product{background:#fff;border:1px solid #ece8e0;border-radius:6px;overflow:hidden;transition:box-shadow .2s,transform .2s;padding-bottom:14px!important}
.woocommerce ul.products li.product:hover{box-shadow:0 6px 24px rgba(0,0,0,.09);transform:translateY(-2px)}
.woocommerce ul.products li.product a img{border-radius:0!important;transition:transform .35s}
.woocommerce ul.products li.product:hover img{transform:scale(1.03)}
.woocommerce ul.products li.product .woocommerce-loop-product__title{font-size:.9rem!important;font-weight:600!important;color:#1a1a1a!important;padding:10px 12px 4px!important;line-height:1.35}
.woocommerce ul.products li.product .button.cc-enquiry-btn{display:block;width:calc(100% - 24px);margin:8px 12px 0;text-align:center;box-sizing:border-box;font-size:.82rem!important;padding:8px 16px!important}

/* Enquiry button */
.cc-enquiry-btn{transition:background .2s ease,transform .1s ease}
.cc-enquiry-btn:hover{background:#9a7209!important;transform:translateY(-1px);color:#fff!important}

/* Breadcrumb */
.woocommerce .woocommerce-breadcrumb{font-size:.8rem;color:#888;margin-bottom:1rem}
.woocommerce .woocommerce-breadcrumb a{color:#888}
.woocommerce .woocommerce-breadcrumb a:hover{color:#b8960c}

/* Product title */
.woocommerce div.product .product_title{font-size:clamp(1.4rem,3vw,2rem)!important;font-weight:700!important;color:#1a1a1a!important;line-height:1.3;margin-bottom:.5rem}

/* Short description */
.woocommerce div.product .woocommerce-product-details__short-description{font-size:.95rem;color:#555;line-height:1.7;margin-bottom:1.4rem;border-left:3px solid #b8960c;padding-left:.9em}
.woocommerce div.product .woocommerce-product-details__short-description p{margin:0}

/* Product gallery */
.woocommerce div.product div.images .woocommerce-product-gallery__image{border:1px solid #ece8e0;border-radius:4px;overflow:hidden}
.woocommerce div.product div.images .flex-control-thumbs li img{border-radius:3px;opacity:.7;border:2px solid transparent;transition:opacity .2s,border-color .2s}
.woocommerce div.product div.images .flex-control-thumbs li img:hover,
.woocommerce div.product div.images .flex-control-thumbs li img.flex-active{opacity:1;border-color:#b8960c}
.woocommerce div.product div.summary{padding-left:2rem}
@media(max-width:768px){.woocommerce div.product div.summary{padding-left:0}}

/* Sidebar */
.woocommerce .widget_product_categories .product-categories{list-style:none;padding:0;margin:0}
.woocommerce .widget_product_categories li{border-bottom:1px solid #f0ebe3;padding:6px 0}
.woocommerce .widget_product_categories li a{color:#444;font-size:.88rem;transition:color .15s}
.woocommerce .widget_product_categories li a:hover,.woocommerce .widget_product_categories .current-cat>a{color:#b8960c;font-weight:600}

/* Enquiry form */
.elementor-form .elementor-field-group{margin-bottom:1.2rem}
.elementor-form .elementor-field-label{font-size:.85rem;font-weight:600;color:#333;margin-bottom:.3rem}
.elementor-form .elementor-field-textual,.elementor-form .elementor-field-select{border:1px solid #d8d2c8!important;border-radius:3px!important;padding:10px 14px!important;font-size:.9rem!important;transition:border-color .2s!important}
.elementor-form .elementor-field-textual:focus,.elementor-form .elementor-field-select:focus{border-color:#b8960c!important;outline:none}
.elementor-form .elementor-button[type="submit"]{background:#b8960c!important;color:#fff!important;font-weight:600!important;border-radius:3px!important;padding:12px 32px!important;letter-spacing:.05em;transition:background .2s,transform .15s!important}
.elementor-form .elementor-button[type="submit"]:hover{background:#8a6e0a!important;transform:translateY(-1px)}

/* Category page header */
.woocommerce-products-header__title{font-size:clamp(1.4rem,3vw,2rem);font-weight:700;color:#1a1a1a;margin-bottom:.5rem}
.woocommerce-products-header .woocommerce-product-subcategories{display:none}

/* Pagination */
.woocommerce nav.woocommerce-pagination ul li a,.woocommerce nav.woocommerce-pagination ul li span{color:#444!important;border-color:#e0d9cf!important;font-size:.88rem}
.woocommerce nav.woocommerce-pagination ul li span.current{background:#b8960c!important;border-color:#b8960c!important;color:#fff!important}

/* Woolentor widget */
.wl-product-wrap{border:1px solid #ece8e0!important;border-radius:6px!important;overflow:hidden;transition:box-shadow .2s,transform .2s!important}
.wl-product-wrap:hover{box-shadow:0 6px 20px rgba(0,0,0,.1)!important;transform:translateY(-2px)!important}
.wl-product-wrap .wl-product-title a{font-size:.88rem!important;line-height:1.4!important;font-weight:500!important;color:#222!important}

/* Language switcher pill */
.lang-switcher-en>a.elementor-item{font-size:.78rem!important;font-weight:600!important;letter-spacing:.08em;border:1px solid currentColor!important;border-radius:3px!important;padding:3px 9px!important;opacity:.75;transition:opacity .18s!important}
.lang-switcher-en>a.elementor-item:hover{opacity:1}
